import{_ as n,c as a,o as p,aj as t}from"./chunks/framework.CynFBi0q.js";const o=JSON.parse('{"title":"第5章 搭建产品架构 — 1张表、4张图","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-product/chapter_5.md","filePath":"handbook/ai-product/chapter_5.md","lastUpdated":1782008855000}'),e={name:"handbook/ai-product/chapter_5.md"};function l(i,s,d,r,b,c){return p(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="第5章-搭建产品架构-—-1张表、4张图" tabindex="-1">第5章 搭建产品架构 — 1张表、4张图 <a class="header-anchor" href="#第5章-搭建产品架构-—-1张表、4张图" aria-label="Permalink to “第5章 搭建产品架构 — 1张表、4张图”">​</a></h1><p>产品经理最怕的场景是什么？评审会上，开发问&quot;这个功能的状态有哪些？&quot;，你愣住了。改需求时，产品说&quot;这个流程好像不太对&quot;，你发现想不全。这不是能力问题，是架构没搭好。</p><p>我是怕浪猫，这一章不讲理论，只讲实操。1张表、4张图，帮你把任何产品的架构搭得清清楚楚。</p><h2 id="_5-1-产品架构方法论" tabindex="-1">5.1 产品架构方法论 <a class="header-anchor" href="#_5-1-产品架构方法论" aria-label="Permalink to “5.1 产品架构方法论”">​</a></h2><h3 id="_5-1-1-产品架构的本质与价值" tabindex="-1">5.1.1 产品架构的本质与价值 <a class="header-anchor" href="#_5-1-1-产品架构的本质与价值" aria-label="Permalink to “5.1.1 产品架构的本质与价值”">​</a></h3><p>产品架构是什么？简单说就是&quot;把产品的所有要素组织起来的结构&quot;。</p><p>为什么要画产品架构？因为人脑处理不了太复杂的信息。产品经理脑子里装着200个功能点、50个流程节点、30个角色——不画出来，根本理不清。</p><p>产品架构的三个价值：</p><p><strong>第一：系统化思考的工具</strong></p><p>画架构的过程就是强迫自己思考的过程。&quot;内容模块和用户模块是什么关系？搜索功能依赖哪些基础能力？&quot;架构图画着画着，这些问题就想清楚了。</p><p><strong>第二：团队沟通的媒介</strong></p><p>PRD评审时，一图胜千言。你花10分钟讲清楚架构图，比写1000字的设计说明更有用。开发、设计、测试看了架构图，就知道你要做什么。</p><p><strong>第三：迭代决策的依据</strong></p><p>产品迭代时，架构图告诉你&quot;改A会影响B&quot;。你知道改动的影响范围，才能做决策。没有架构图，改了一个地方可能引发三个地方的问题。</p><blockquote><p>产品架构不是&quot;写完就完了&quot;的文档，而是&quot;一直在用&quot;的工具。好的架构图，每次迭代都应该拿出来对照。</p></blockquote><h3 id="_5-1-2-1张表-功能清单-需求矩阵" tabindex="-1">5.1.2 1张表：功能清单/需求矩阵 <a class="header-anchor" href="#_5-1-2-1张表-功能清单-需求矩阵" aria-label="Permalink to “5.1.2 1张表：功能清单/需求矩阵”">​</a></h3><p>功能清单表是产品架构的&quot;地基&quot;。没有这张表，所有架构图都是空中楼阁。</p><p><strong>功能清单表的结构</strong></p><table tabindex="0"><thead><tr><th>ID</th><th>模块</th><th>功能名称</th><th>功能描述</th><th>用户角色</th><th>优先级</th><th>依赖功能</th></tr></thead><tbody><tr><td>F001</td><td>用户</td><td>注册</td><td>手机号+验证码注册</td><td>访客</td><td>P0</td><td>无</td></tr><tr><td>F002</td><td>用户</td><td>登录</td><td>手机号+验证码登录</td><td>访客</td><td>P0</td><td>F001</td></tr><tr><td>F003</td><td>内容</td><td>发帖</td><td>发布图文/视频内容</td><td>创作者</td><td>P0</td><td>F001,F002</td></tr><tr><td>F004</td><td>内容</td><td>浏览</td><td>列表流浏览内容</td><td>消费者</td><td>P0</td><td>无</td></tr><tr><td>F005</td><td>内容</td><td>评论</td><td>对内容发表评论</td><td>消费者</td><td>P1</td><td>F001,F004</td></tr></tbody></table><p><strong>模块划分方法</strong></p><p>模块划分有两种思路：</p><p>思路一：按业务域划分。适合复杂业务系统。</p><table tabindex="0"><thead><tr><th>业务域</th><th>说明</th><th>模块示例</th></tr></thead><tbody><tr><td>用户域</td><td>用户相关的一切</td><td>注册、登录、资料、会员</td></tr><tr><td>内容域</td><td>内容生产与消费</td><td>发帖、浏览、搜索、推荐</td></tr><tr><td>交易域</td><td>交易与支付</td><td>购物车、订单、支付、售后</td></tr><tr><td>社交域</td><td>社交互动</td><td>点赞、评论、关注、消息</td></tr></tbody></table><p>思路二：按页面/功能入口划分。适合C端产品。</p><table tabindex="0"><thead><tr><th>入口</th><th>包含功能</th></tr></thead><tbody><tr><td>首页Tab</td><td>推荐流、分类入口、搜索入口</td></tr><tr><td>搜索Tab</td><td>搜索框、历史记录、搜索结果</td></tr><tr><td>发布Tab</td><td>发布器、内容编辑、话题选择</td></tr><tr><td>消息Tab</td><td>评论、赞、关注、系统通知</td></tr><tr><td>我的Tab</td><td>个人信息、设置、钱包、订单</td></tr></tbody></table><p><strong>功能清单表的自检标准</strong></p><p>画完功能清单表后，问自己三个问题：</p><ol><li>每一行都有明确的用户角色吗？没有用户角色的功能是&quot;假功能&quot;——你以为自己需要，其实没人用。</li><li>每一行都有清晰的优先级吗？P0/P1/P2/P3，不是给老板看的，是给自己排版本用的。</li><li>依赖关系是否完整？任何一个P0功能，如果依赖了P2功能，优先级应该提升。</li></ol><h3 id="_5-1-3-4张图-信息架构图、功能架构图、业务流程图、状态机图" tabindex="-1">5.1.3 4张图：信息架构图、功能架构图、业务流程图、状态机图 <a class="header-anchor" href="#_5-1-3-4张图-信息架构图、功能架构图、业务流程图、状态机图" aria-label="Permalink to “5.1.3 4张图：信息架构图、功能架构图、业务流程图、状态机图”">​</a></h3><p>这四张图是产品架构的核心表达。</p><p><strong>图1：信息架构图</strong></p><p>信息架构图回答的问题是：&quot;产品里有哪些信息，这些信息之间是什么关系？&quot;</p><p>以电商App为例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>商品信息</span></span>
<span class="line"><span>├── 商品基础信息（名称、价格、库存）</span></span>
<span class="line"><span>├── 商品详情信息（图片、描述、规格）</span></span>
<span class="line"><span>└── 商品评价信息（评分、评价内容）</span></span>
<span class="line"><span>用户信息</span></span>
<span class="line"><span>├── 账户信息（手机、密码、昵称）</span></span>
<span class="line"><span>├── 收货信息（地址簿）</span></span>
<span class="line"><span>└── 资产信息（积分、优惠券、余额）</span></span>
<span class="line"><span>订单信息</span></span>
<span class="line"><span>├── 订单基础信息（订单号、时间、状态）</span></span>
<span class="line"><span>├── 订单商品信息（商品快照、数量）</span></span>
<span class="line"><span>└── 订单支付信息（支付方式、金额）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>信息架构图的价值：帮助设计师理解&quot;数据模型&quot;，帮助开发理解&quot;数据库设计&quot;。好的信息架构是前后端沟通的基础。</p><p><strong>图2：功能架构图</strong></p><p>功能架构图回答的问题是：&quot;产品的功能是怎么组织的？哪些是底层能力，哪些是上层应用？&quot;</p><p>以内容平台为例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│              内容展示层                   │</span></span>
<span class="line"><span>│  [首页推荐] [搜索结果] [个人主页] [详情页]  │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span>
<span class="line"><span>                      ↑</span></span>
<span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│              内容运营层                   │</span></span>
<span class="line"><span>│  [话题管理] [内容审核] [推荐算法] [搜索排序] │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span>
<span class="line"><span>                      ↑</span></span>
<span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│              内容供给层                   │</span></span>
<span class="line"><span>│  [发布器] [内容处理] [媒资管理] [创作者工具] │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span>
<span class="line"><span>                      ↑</span></span>
<span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│              基础能力层                   │</span></span>
<span class="line"><span>│  [用户体系] [权限体系] [通知体系] [数据分析] │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p>功能架构图的价值：让你看清楚&quot;复用关系&quot;。如果两个功能都要用&quot;搜索排序&quot;，你应该把搜索排序做成底层能力，而不是重复实现两次。</p><p><strong>图3：业务流程图</strong></p><p>业务流程图回答的问题是：&quot;用户做一件事，要经历哪些步骤，每一步是什么？&quot;</p><p>以电商下单流程为例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>开始 → 浏览商品 → 点击详情 → 选择规格 → 加入购物车 → </span></span>
<span class="line"><span>去购物车结算 → 确认订单 → 选择地址 → 选择支付方式 → </span></span>
<span class="line"><span>确认支付 → 跳转支付 → 支付成功 → 生成订单 → 结束</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>扩展流程：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>加入购物车</span></span>
<span class="line"><span>├── 库存充足 → 加入成功</span></span>
<span class="line"><span>├── 库存不足 → 提示&quot;已售罄&quot; / &quot;到货通知&quot;</span></span>
<span class="line"><span>└── 未登录 → 跳转登录 → 登录后继续</span></span>
<span class="line"><span></span></span>
<span class="line"><span>确认支付</span></span>
<span class="line"><span>├── 余额充足 → 支付成功</span></span>
<span class="line"><span>├── 余额不足 → 提示&quot;余额不足&quot;</span></span>
<span class="line"><span>└── 支付超时 → 订单关闭</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>业务流程图的价值：帮你穷举所有可能。用户走的每一条路，你都要提前想清楚。没有业务流程图，上线后就会出现各种&quot;没想到的bug&quot;。</p><p><strong>图4：状态机图</strong></p><p>状态机图回答的问题是：&quot;一个实体（订单、内容、用户）有哪些状态，这些状态之间是怎么转换的？&quot;</p><p>以订单状态机为例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[待付款] --付款成功--&gt; [待发货] --商家发货--&gt; [待收货] --确认收货--&gt; [已完成]</span></span>
<span class="line"><span>    ↑                    |                    |</span></span>
<span class="line"><span>    └─────取消/退款───────┴───申请退款─────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>更复杂的状态机（考虑退货）：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[待付款]</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ↓ 付款成功</span></span>
<span class="line"><span>[待发货]</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ↓ 商家发货</span></span>
<span class="line"><span>[待收货]</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─→[确认收货]→[已完成]</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─→[申请退款/退货]→[退款/退货中]</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              ├─→[退款成功]→[已退款]</span></span>
<span class="line"><span>              └─→[退货成功]→[已退货]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>状态机图的价值：开发看了状态机，就知道&quot;每一种状态变化应该触发什么逻辑&quot;。产品经理看了状态机，就知道&quot;哪些状态转换容易出错&quot;。很多订单bug，根源都是状态机没画清楚。</p><blockquote><p>四张图不是&quot;全部要画&quot;，而是&quot;根据需要选择&quot;。C端产品优先画业务流程图和状态机图。B端产品优先画功能架构图和信息架构图。没有标准答案，只有最适合你的选择。</p></blockquote><p><strong>四张图的适用场景</strong></p><table tabindex="0"><thead><tr><th>图类型</th><th>回答的问题</th><th>最适合的产品</th><th>优先级</th></tr></thead><tbody><tr><td>信息架构图</td><td>有哪些数据？</td><td>B端、平台型产品</td><td>中</td></tr><tr><td>功能架构图</td><td>功能如何组织？</td><td>所有产品</td><td>高</td></tr><tr><td>业务流程图</td><td>流程是什么？</td><td>C端、交易类产品</td><td>高</td></tr><tr><td>状态机图</td><td>状态有哪些？</td><td>有状态变化的实体</td><td>高</td></tr></tbody></table><h2 id="_5-2-产品架构实战" tabindex="-1">5.2 产品架构实战 <a class="header-anchor" href="#_5-2-产品架构实战" aria-label="Permalink to “5.2 产品架构实战”">​</a></h2><h3 id="_5-2-1-思维导图与流程图工具运用" tabindex="-1">5.2.1 思维导图与流程图工具运用 <a class="header-anchor" href="#_5-2-1-思维导图与流程图工具运用" aria-label="Permalink to “5.2.1 思维导图与流程图工具运用”">​</a></h3><p>好的工具让架构设计效率提升10倍。我用过的工具里，有三个最推荐。</p><p><strong>工具一：XMind（思维导图）</strong></p><p>适合画：功能清单表、信息架构图、功能架构图</p><p>XMind的优势是结构清晰、层次分明，适合梳理&quot;包含关系&quot;——&quot;A模块包含B和C，B包含D和E&quot;。缺点是对流程图和状态机图支持不好。</p><p>使用技巧：用XMind的&quot;大纲模式&quot;直接生成功能清单。每一行包含&quot;模块/功能/描述/优先级&quot;，在XMind里一目了然。</p><p><strong>工具二：ProcessOn（在线流程图）</strong></p><p>适合画：业务流程图、状态机图</p><p>ProcessOn的优势是在线协作，团队可以同时编辑。模板库丰富，直接选用模板改一改就行。缺点是需要联网，离线体验一般。</p><p>使用技巧：用ProcessOn的泳道图来画跨角色的流程。每个泳道代表一个角色，横向看就能看到每个角色的工作。</p><p><strong>工具三：Figma（设计协作）</strong></p><p>适合画：所有类型的图（如果你愿意的话）</p><p>Figma的优势是设计工具的精度，适合画需要给设计师参考的架构图。缺点是学习曲线稍高，不如前两者&quot;轻量&quot;。</p><p>使用技巧：用Figma的框架工具画信息架构图。框架内可以嵌套框架，层次关系很清楚。</p><h3 id="_5-2-2-实战案例-资讯app产品架构搭建" tabindex="-1">5.2.2 实战案例：资讯App产品架构搭建 <a class="header-anchor" href="#_5-2-2-实战案例-资讯app产品架构搭建" aria-label="Permalink to “5.2.2 实战案例：资讯App产品架构搭建”">​</a></h3><p>用一个完整的案例，把&quot;1张表、4张图&quot;串起来。</p><p><strong>背景</strong></p><p>做一个面向职场人士的新闻资讯App，核心功能：新闻浏览、话题讨论、个人中心。</p><p><strong>步骤一：功能清单表</strong></p><table tabindex="0"><thead><tr><th>ID</th><th>模块</th><th>功能名称</th><th>功能描述</th><th>用户角色</th><th>优先级</th></tr></thead><tbody><tr><td>F001</td><td>首页</td><td>推荐流</td><td>算法推荐新闻</td><td>消费者</td><td>P0</td></tr><tr><td>F002</td><td>首页</td><td>分类浏览</td><td>按分类查看新闻</td><td>消费者</td><td>P1</td></tr><tr><td>F003</td><td>首页</td><td>搜索</td><td>搜索新闻和话题</td><td>消费者</td><td>P1</td></tr><tr><td>F004</td><td>详情</td><td>新闻阅读</td><td>阅读新闻正文</td><td>消费者</td><td>P0</td></tr><tr><td>F005</td><td>详情</td><td>评论</td><td>对新闻发表评论</td><td>消费者</td><td>P0</td></tr><tr><td>F006</td><td>详情</td><td>收藏</td><td>收藏新闻</td><td>消费者</td><td>P1</td></tr><tr><td>F007</td><td>话题</td><td>话题列表</td><td>浏览热门话题</td><td>消费者</td><td>P1</td></tr><tr><td>F008</td><td>话题</td><td>话题讨论</td><td>在话题下参与讨论</td><td>消费者</td><td>P1</td></tr><tr><td>F009</td><td>用户</td><td>登录注册</td><td>账户体系</td><td>访客/用户</td><td>P0</td></tr><tr><td>F010</td><td>用户</td><td>个人信息</td><td>修改昵称头像等</td><td>用户</td><td>P1</td></tr><tr><td>F011</td><td>用户</td><td>收藏管理</td><td>管理收藏的新闻</td><td>用户</td><td>P1</td></tr><tr><td>F012</td><td>用户</td><td>阅读历史</td><td>查看历史浏览记录</td><td>用户</td><td>P2</td></tr></tbody></table><p><strong>步骤二：信息架构图</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户数据</span></span>
<span class="line"><span>├── 账户（手机号、密码、第三方绑定）</span></span>
<span class="line"><span>├── 资料（昵称、头像、简介）</span></span>
<span class="line"><span>├── 行为（收藏记录、阅读历史）</span></span>
<span class="line"><span>└── 社交（关注、粉丝）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>内容数据</span></span>
<span class="line"><span>├── 新闻（标题、正文、作者、来源、发布时间）</span></span>
<span class="line"><span>├── 分类（分类ID、名称、图标）</span></span>
<span class="line"><span>├── 评论（内容、用户、新闻、时间）</span></span>
<span class="line"><span>└── 话题（标题、描述、参与人数、热度）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系统数据</span></span>
<span class="line"><span>├── 推送记录</span></span>
<span class="line"><span>├── 广告配置</span></span>
<span class="line"><span>└── 内容推荐模型</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p><strong>步骤三：功能架构图</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌────────────────────┐</span></span>
<span class="line"><span>│      内容展示层      │</span></span>
<span class="line"><span>│  [首页推荐] [分类] [搜索] [话题] │</span></span>
<span class="line"><span>└────────────────────┘</span></span>
<span class="line"><span>         ↑</span></span>
<span class="line"><span>┌────────────────────┐</span></span>
<span class="line"><span>│      内容运营层      │</span></span>
<span class="line"><span>│  [内容推荐] [搜索排序] [话题热度] │</span></span>
<span class="line"><span>└────────────────────┘</span></span>
<span class="line"><span>         ↑</span></span>
<span class="line"><span>┌────────────────────┐</span></span>
<span class="line"><span>│      内容供给层      │</span></span>
<span class="line"><span>│  [新闻采集] [内容处理] [内容审核] │</span></span>
<span class="line"><span>└────────────────────┘</span></span>
<span class="line"><span>         ↑</span></span>
<span class="line"><span>┌────────────────────┐</span></span>
<span class="line"><span>│      基础能力层      │</span></span>
<span class="line"><span>│  [用户] [权限] [搜索] [推送] [数据] │</span></span>
<span class="line"><span>└────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p><strong>步骤四：业务流程图</strong></p><p>核心流程——阅读新闻：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>打开App → 首页推荐流 → 点击新闻卡片 → 进入详情页 → 阅读正文 → </span></span>
<span class="line"><span>发表评论 → 收藏 → 返回首页 → 浏览其他内容 → 退出App</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>扩展流程——搜索新闻：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>点击搜索入口 → 输入关键词 → 展示搜索建议 → 点击搜索 → </span></span>
<span class="line"><span>加载搜索结果 → 点击结果 → 进入详情页</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>异常流程——新闻加载失败：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>点击新闻卡片 → 加载中（3秒）→ 加载失败（超时/网络异常）→ </span></span>
<span class="line"><span>显示错误页 → 重试按钮 → 重试加载 → 加载成功</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>步骤五：状态机图</strong></p><p>评论状态机：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[待发布] --点击发送--&gt; [发布中]</span></span>
<span class="line"><span>                           ↓ 成功</span></span>
<span class="line"><span>                       [已发布] --被删除--&gt; [已删除]</span></span>
<span class="line"><span>                           ↓ 被举报</span></span>
<span class="line"><span>                       [审核中] --通过--&gt; [已发布]</span></span>
<span class="line"><span>                                      --不通过--&gt; [已删除]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>收藏状态机：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[未收藏] --点击收藏--&gt; [已收藏]</span></span>
<span class="line"><span>                         ↓</span></span>
<span class="line"><span>                   [取消收藏] --&gt; [未收藏]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><blockquote><p>架构设计不是&quot;一次性完成&quot;的工作，而是在产品迭代中持续完善的。新功能上线后要更新架构图，改了架构图要同步更新PRD——保持文档的一致性，比文档本身更重要。</p></blockquote><p><strong>产品架构迭代检查清单</strong></p><table tabindex="0"><thead><tr><th>检查项</th><th>频率</th><th>说明</th></tr></thead><tbody><tr><td>功能清单更新</td><td>每次版本规划时</td><td>新增功能加入清单</td></tr><tr><td>信息架构更新</td><td>涉及数据结构变更时</td><td>和开发对齐数据模型</td></tr><tr><td>流程图更新</td><td>流程发生重大变更时</td><td>老流程作废，新流程替换</td></tr><tr><td>状态机更新</td><td>涉及状态变更时</td><td>和开发对齐状态逻辑</td></tr></tbody></table><hr><p>本章小结：产品架构是产品经理的&quot;底层能力&quot;。1张表（功能清单表）把你要做的事情列清楚，4张图（信息架构图、功能架构图、业务流程图、状态机图）从四个维度把产品结构表达清楚。架构清晰了，后面的设计、评审、开发才会顺畅。</p><table tabindex="0"><thead><tr><th>本章核心知识点</th><th>一句话总结</th></tr></thead><tbody><tr><td>功能清单表</td><td>所有功能的完整列表，含优先级和依赖</td></tr><tr><td>信息架构图</td><td>产品有哪些数据，数据之间的关系</td></tr><tr><td>功能架构图</td><td>功能如何分层组织，底层和上层的关系</td></tr><tr><td>业务流程图</td><td>用户做一件事的完整路径，含分支和异常</td></tr><tr><td>状态机图</td><td>一个实体的所有状态，以及状态之间的转换关系</td></tr><tr><td>工具选择</td><td>XMind梳理结构，ProcessOn画流程，Figma做精细设计</td></tr></tbody></table><p>觉得有用？收藏起来，下次画产品架构直接照抄模板。</p><p>你画架构图时踩过什么坑？评论区说说。</p><p>关注怕浪猫，下期我们讲&quot;交互原型设计&quot;——Axure怎么用、原型怎么画、交互状态怎么设计，怕浪猫带你从零开始搞定原型。</p><p>系列进度 5/16</p><p><strong>下章预告：</strong> 第6章是产品经理的手艺活。原型的画法看似简单，但大多数人画出来的原型——要么太简陋（没有交互），要么太花哨（开发做不出来）。下一章，我教你如何画一个&quot;开发看了就知道怎么做&quot;的原型。</p>`,105)])])}const h=n(e,[["render",l]]);export{o as __pageData,h as default};
